namespace sv_528dbabab61d4c85ba098bdee74c2fe7.Services;

public sealed class WarehouseStateService : IDisposable
{
    public static IReadOnlyList<(string Id, string Name)> AvailableWarehouses { get; } =
    [
        ("wh-a", "Warehouse A"),
        ("wh-b", "Warehouse B"),
        ("wh-c", "Warehouse C"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;

        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }

    public void Dispose() => OnChange = null;
}

namespace sv_528dbabab61d4c85ba098bdee74c2fe7.Services;

public sealed class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();

    public int LastAlertCount { get; private set; }

    public event Action? OnAlertCountChanged;

    /// <summary>
    /// Simulates a database query returning the number of items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Stores the latest count and notifies all subscribers.
    /// Called by whichever component owns the polling loop.
    /// </summary>
    public void PublishAlertCount(int count)
    {
        LastAlertCount = count;
        OnAlertCountChanged?.Invoke();
    }

    public void Dispose() => OnAlertCountChanged = null;
}

