@using sv_528dbabab61d4c85ba098bdee74c2fe7.Services
@inject WarehouseStateService WarehouseState
@implements IDisposable

<div class="d-flex align-items-center">
    <label class="me-2 text-nowrap fw-semibold" for="warehouse-select">Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            style="width: auto;"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseStateService.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            WarehouseState.SetWarehouse(id);
        }
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@using sv_528dbabab61d4c85ba098bdee74c2fe7.Services
@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.LastAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-2">@AlertService.LastAlertCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-2">0</span>
}

@code {
    protected override void OnInitialized()
    {
        AlertService.OnAlertCountChanged += OnCountChanged;
    }

    private async void OnCountChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= OnCountChanged;
    }
}

