@page "/dashboard"
@rendermode InteractiveServer

@using sv_528dbabab61d4c85ba098bdee74c2fe7.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard – @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">
            Current Site: <strong>@WarehouseState.CurrentWarehouseName</strong>
        </h5>
        <p class="card-text">
            Low-stock alerts:
            @if (AlertService.LastAlertCount > 0)
            {
                <span class="badge bg-danger fs-6">@AlertService.LastAlertCount items below minimum</span>
            }
            else
            {
                <span class="badge bg-success fs-6">All stock levels OK</span>
            }
        </p>
        <small class="text-muted">
            Polling every 10 seconds. Last check: @_lastCheck?.ToString("T")
        </small>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private DateTime? _lastCheck;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertCountChanged += OnAlertCountChanged;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            StartPolling();
        }
    }

    private async void OnWarehouseChanged()
    {
        // Warehouse changed — restart polling so the first tick is immediate.
        StopPolling();
        StartPolling();
        await InvokeAsync(StateHasChanged);
    }

    private async void OnAlertCountChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    private async void StartPolling()
    {
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        while (!token.IsCancellationRequested)
        {
            try
            {
                var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
                _lastCheck = DateTime.Now;

                // Broadcast the result to every subscriber (sidebar badge, this page, etc.)
                AlertService.PublishAlertCount(count);
            }
            catch (Exception) when (token.IsCancellationRequested)
            {
                break;
            }

            try
            {
                await Task.Delay(TimeSpan.FromSeconds(10), token);
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        StopPolling();
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertCountChanged -= OnAlertCountChanged;
    }
}

